import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("Claim Office", () => {
  describe("quote", () => {
    it("should return premium of 5 G for an empty item list (processing fee only)", () => {
      const scenario = {
        customer: { years: 0 },
        steps: [{ type: "quote", items: [] }],
      };
      const result = processScenario(scenario);
      expect(result.results[0].premium).toBe(5);
    });

    it.todo("should return base premium plus processing fee for a single sword");

    it.todo("should return base premium plus processing fee for a single amulet");

    it.todo("should return base premium plus processing fee for a single staff");

    it.todo("should return base premium plus processing fee for a single potion");

    it.todo("should return 25 G base premium per individual component");

    it.todo("should apply building block discount of 60 G for exactly 3 alike components");

    it.todo("should sum base premiums of multiple different items");

    it.todo("should add 50% cursed surcharge to the cursed item base premium only");

    it.todo("should add 30% high enchantment surcharge for enchantment level 5 or above");

    it.todo("should apply both cursed and high enchantment surcharges to the same item");

    it.todo("should add 10% first insurance surcharge to every item in every quote");

    it.todo("should apply 20% loyalty discount for customers with 2 or more years");

    it.todo("should apply 15% follow-up contract discount on second and subsequent quotes");

    it.todo("should round final premium up to whole G in MHPCO favor");

    it.todo("should compute 165 G for newcomer with cursed sword (integration)");

    it.todo("should compute 160 G for long-standing customer second contract with cursed enchanted sword (integration)");
  });

  describe("claim", () => {
    it.todo("should subtract 100 G deductible from damage for a standard item");

    it.todo("should reimburse at 50% for items with enchantment level 8 or above then apply deductible");

    it.todo("should fully reimburse dragon material items then apply deductible");

    it.todo("should apply 50% rule when both dragon material and enchantment >= 8 apply");

    it.todo("should apply 100 G deductible per damaged item when multiple items are damaged");

    it.todo("should cap total payout at twice the insurance sum");

    it.todo("should reduce payout to remaining cap when cap is partially exhausted by prior claim");

    it.todo("should round payout down to whole G in MHPCO favor");
  });
});

