interface Item {
  type: string;
}

interface Step {
  type: string;
  items: Item[];
}

interface Scenario {
  customer: { years: number };
  steps: Step[];
}

interface Result {
  premium: number;
}

interface ScenarioOutput {
  results: Result[];
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

export function processScenario(scenario: Scenario): ScenarioOutput {
  const step = scenario.steps[0];
  let basePremium = 0;
  for (const item of step.items) {
    basePremium += BASE_PREMIUMS[item.type];
  }
  const premium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
  return { results: [{ premium }] };
}

