interface Item {
  type: string;
}

interface Step {
  type: string;
  items: Item[];
}

interface Scenario {
  customer: { years: number };
  steps: Step[];
}

interface Result {
  premium: number;
}

interface ScenarioOutput {
  results: Result[];
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const BUILDING_BLOCK_PREMIUM = 60;
const BUILDING_BLOCK_SIZE = 3;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const countItemsByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] || 0) + 1;
  }
  return counts;
};

const calculateBasePremium = (items: Item[]): number => {
  const typeCounts = countItemsByType(items);
  let total = 0;

  for (const [type, count] of Object.entries(typeCounts)) {
    if (count === BUILDING_BLOCK_SIZE) {
      total += BUILDING_BLOCK_PREMIUM;
    } else {
      total += BASE_PREMIUMS[type] * count;
    }
  }

  return total;
};

export function processScenario(scenario: Scenario): ScenarioOutput {
  const step = scenario.steps[0];
  const basePremium = calculateBasePremium(step.items);
  const premium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
  return { results: [{ premium }] };
}

