interface Item {
  type: string;
  cursed?: boolean;
  enchantment?: number;
}

interface Step {
  type: string;
  items: Item[];
}

interface Scenario {
  customer: { years: number };
  steps: Step[];
}

interface Result {
  premium: number;
}

interface ScenarioOutput {
  results: Result[];
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const BUILDING_BLOCK_PREMIUM = 60;
const BUILDING_BLOCK_SIZE = 3;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const groupItemsByType = (items: Item[]): Record<string, Item[]> => {
  const groups: Record<string, Item[]> = {};
  for (const item of items) {
    if (!groups[item.type]) {
      groups[item.type] = [];
    }
    groups[item.type].push(item);
  }
  return groups;
};

const calculateSingleItemPremium = (item: Item): number => {
  const basePremium = BASE_PREMIUMS[item.type];
  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
  const enchantmentSurcharge =
    item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
      ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
      : 0;
  return basePremium + cursedSurcharge + enchantmentSurcharge;
};

const calculateItemsPremium = (items: Item[]): number => {
  const itemsByType = groupItemsByType(items);
  let total = 0;

  for (const [_type, typeItems] of Object.entries(itemsByType)) {
    if (typeItems.length === BUILDING_BLOCK_SIZE) {
      total += BUILDING_BLOCK_PREMIUM;
    } else {
      for (const item of typeItems) {
        total += calculateSingleItemPremium(item);
      }
    }
  }

  return total;
};

const calculateStepPremium = (
  step: Step,
  customerYears: number,
  isFollowUp: boolean,
): number => {
  const itemsPremium = calculateItemsPremium(step.items);
  const surcharge = itemsPremium * FIRST_INSURANCE_SURCHARGE_RATE;
  const loyaltyDiscount =
    customerYears >= LOYALTY_YEARS_THRESHOLD
      ? itemsPremium * LOYALTY_DISCOUNT_RATE
      : 0;
  const followUpDiscount = isFollowUp ? itemsPremium * FOLLOW_UP_DISCOUNT_RATE : 0;
  return itemsPremium + surcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
};

export function processScenario(scenario: Scenario): ScenarioOutput {
  const results = scenario.steps.map((step, index) => {
    const premium = calculateStepPremium(step, scenario.customer.years, index > 0);
    return { premium };
  });
  return { results };
}

